mapper.select:
select u.user_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time,u.area,u.career,u.age,u.remark, u.union_id, u.open_id from sys_user u
where u.del_flag = '0'

	AND u.user_id = #{userId}


	AND u.user_name like concat('%', #{userName}, '%')


	AND u.status = #{status}


	AND u.open_id = #{openId}


	AND u.area like concat('%', #{area}, '%')


	AND u.career like concat('%', #{career}, '%')


  and age >= #{age}


	AND u.phonenumber like concat('%', #{phonenumber}, '%')


	AND date_format(u.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


	AND date_format(u.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


${params.dataScope}

select distinct u.user_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.status, u.create_time from sys_user u left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and r.role_id = #{roleId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.phonenumber like concat('%', #{phonenumber}, '%')
${params.dataScope}

mapper.update:
update sys_user
user_name = #{userName}, nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, area = #{area}, career = #{career}, age = #{age}, update_time = sysdate()
where user_id = #{userId}
